///////////////////////////////////////////////////////////////////////////////
//  Fermilab National Accelerator Laboratory
///////////////////////////////////////////////////////////////////////////////
// Description:
//   QickEmu-driven testbench for QICK project — Vivado/Xilinx-IP compatible.
//   Adapted from tb_qick.sv: keeps all real Xilinx RTL blocks but replaces
//   hardcoded VIP transactions with file-based replay from QickEmu.prepare().
//
// Required input files (generated by QickEmu.prepare() + export_vivado_files()):
//   EMU_DIR/pmem.mem         — tproc program memory  (hex, $readmemh)
//   EMU_DIR/wmem.mem         — tproc wave memory     (hex, $readmemh)
//   EMU_DIR/sgmem_ch{N}.mem  — SG envelope table     (signed decimal I,Q CSV)
//   EMU_DIR/axi_replay.txt   — AXI-Lite replay log   (hex addr/data pairs)
//
// Python workflow:
//   from qick_emu import QickEmu
//   emu = QickEmu("qick_config.json")
//   soc = emu.make_soc(memdir="emulator/")
//   soc.tproc.set_lfsr_cfg(2)
//   emu.prepare(prog, soc, memdir="emulator/")
//   emu.export_vivado_files(memdir="emulator/")   # generates axi_replay.txt
//
// Then set EMU_DIR to your "emulator/" directory and simulate.
//////////////////////////////////////////////////////////////////////////////

`timescale 1ns/1fs

`include "_qproc_defines.svh"

import axi_vip_pkg::*;
import axi_mst_0_pkg::*;

// Clock half-periods (ns)
real T_TCLK   =  1.162;   // 430   MHz  tProc dispatcher
real T_CCLK   =    2.5;   // 200   MHz  tProc core
real T_SCLK   =    5.0;   // 100   MHz  PS / AXI
real T_SG_CLK =  0.8346688;   // 600   MHz  signal generator
real T_RO_CLK =  1.62760416;   // 307.2 MHz  readout

// TPROC parameters — must match firmware build
`define GEN_SYNC         1
`define DUAL_CORE        0
`define IO_CTRL          1
`define DEBUG            3
`define TNET             0
`define QCOM             0
`define CUSTOM_PERIPH    2
`define LFSR             1
`define DIVIDER          1
`define ARITH            1
`define TIME_READ        1
`define FIFO_DEPTH       8
`define PMEM_AW          12
`define DMEM_AW          14
`define WMEM_AW          11
`define REG_AW           4
`define IN_PORT_QTY      1
`define OUT_TRIG_QTY     1
`define OUT_DPORT_QTY    1
`define OUT_DPORT_DW     8
`define OUT_WPORT_QTY    5

module tb_qick_emu ();

//----------------------------------------------------
// QickEmu Configuration
//----------------------------------------------------
// Directory containing QickEmu-generated files.
// Can be an absolute path or relative to the Vivado sim run directory.
string EMU_DIR       = "../../../../src/tb";

// How long to let tproc run after AXI replay completes.
// The AXI replay includes the PROC_START command; this is additional wait time.
time   TEST_RUN_TIME = 100us;

// ===========================================================================
// Address Routing Parameters
//
// Must match the base addresses assigned by AddrMap.from_qick_config().
// To get the correct values for your board config, run:
//
//   python3 -c "
//   import json, sys
//   sys.path.insert(0, 'emulator/software/source')
//   cfg = json.load(open('emulator/notebooks/qick_config_216.json'))
//   addr = 0x40000000
//   def add(n,t): global addr; print(f'{n:40s} {t:30s} 0x{addr:08X}'); addr+=0x10000
//   if 'ddr4_buf' in cfg: add(cfg['ddr4_buf']['fullpath'], cfg['ddr4_buf']['type'])
//   if 'mr_buf'   in cfg: add(cfg['mr_buf']['fullpath'],   cfg['mr_buf']['type'])
//   [add(g['fullpath'],g['type']) for g in cfg.get('gens',[])]
//   [(add(r['ro_fullpath'],r['ro_type']),add(r['avgbuf_fullpath'],r['avgbuf_type'])) for r in cfg.get('readouts',[])]
//   [add(t.get('fullpath','qick_processor_0'),t['type']) for t in cfg.get('tprocs',[])]
//   "
//
// Default values below are for ZCU216 HMC demo (qick_config_216.json).
// ===========================================================================

// tproc: qick_processor_0
localparam integer TPROC_BASE  = 32'h40260000;

// Signal generators: all gen IPs occupy a contiguous region.
// Any AXI write to [SG_BASE_LO, SG_BASE_HI) is routed to axi_mst_sg_agent.
// NOTE: tb only instantiates ONE signal gen VIP. Multi-gen writes all drive the
//       same VIP with their per-IP register offset (addr & 0xFFFF).
localparam integer SG_BASE_LO  = 32'h40020000;  // axis_signal_gen_v6_0
localparam integer SG_BASE_HI  = 32'h40120000;  // first non-gen address

// Avg/decim buffers: all avgbuf IPs occupy a contiguous region.
// Any AXI write to [AVG_BASE_LO, AVG_BASE_HI) is routed to axi_mst_avg_agent.
localparam integer AVG_BASE_LO = 32'h40130000;  // axis_avg_buffer_0
localparam integer AVG_BASE_HI = 32'h40260000;  // first non-avgbuf address

//----------------------------------------------------
// VIP Agents
//----------------------------------------------------
axi_mst_0_mst_t  axi_mst_tproc_agent;
axi_mst_0_mst_t  axi_mst_sg_agent;
axi_mst_0_mst_t  axi_mst_avg_agent;
axi_mst_0_mst_t  axi_mst_qemu_agent;

// AXI VIP common variables
xil_axi_prot_t  prot    = 0;
reg [31:0]      data_wr = 32'h12345678;
reg [31:0]      data;
xil_axi_resp_t  resp;

//----------------------------------------------------
// CLK Generation
//----------------------------------------------------
logic c_clk, t_clk, s_ps_dma_aclk;

logic [4:0] dac_fs_gen;
logic       dac_fs, sg_clk;

logic [4:0] adc_fs_gen;
logic       adc_fs, ro_clk;

initial begin t_clk = 1'b0; forever #(T_TCLK*1.0ns) t_clk = ~t_clk; end
initial begin c_clk = 1'b0; forever #(T_CCLK*1.0ns) c_clk = ~c_clk; end
initial begin
   s_ps_dma_aclk = 1'b0;
   #0.5ns;
   forever #(T_SCLK*1.0ns) s_ps_dma_aclk = ~s_ps_dma_aclk;
end

initial begin dac_fs_gen = 'd0; forever #(T_SG_CLK*1.0ns/N_DDS) dac_fs_gen = dac_fs_gen + 'd1; end
assign dac_fs = dac_fs_gen[0];
assign sg_clk = dac_fs_gen[4];

initial begin adc_fs_gen = 'd0; forever #(T_RO_CLK*1.0ns/8.0) adc_fs_gen = adc_fs_gen + 'd1; end
assign adc_fs = adc_fs_gen[0];
assign ro_clk = adc_fs_gen[3];

//----------------------------------------------------
// Reset
//----------------------------------------------------
logic rst_ni;
wire  s_ps_dma_aresetn;
assign s_ps_dma_aresetn = rst_ni;

//----------------------------------------------------
// Signal Declarations
//----------------------------------------------------
reg [255:0]  s_dma_axis_tdata_i;
reg          s_dma_axis_tlast_i;
reg          s_dma_axis_tvalid_i;
reg          m_dma_axis_tready_i;
wire [63:0]  port_0_dt_i;
reg  [63:0]  port_1_dt_i;

logic        m0_axis_tready;
reg          m1_axis_tready = 1;
reg          m2_axis_tready = 1;
reg          m3_axis_tready = 1;
reg          m5_axis_tready = 1;
reg          m6_axis_tready = 1;
reg          m7_axis_tready = 1;

wire         s_dma_axis_tready_o;
wire [255:0] m_dma_axis_tdata_o;
wire         m_dma_axis_tlast_o;
wire         m_dma_axis_tvalid_o;

// tProc wave outputs
wire [167:0] m1_axis_tdata, m2_axis_tdata, m3_axis_tdata;
wire         m1_axis_tvalid, m2_axis_tvalid, m3_axis_tvalid;
wire [167:0] m5_axis_tdata, m6_axis_tdata, m7_axis_tdata;
wire         m5_axis_tvalid, m6_axis_tvalid, m7_axis_tvalid;

wire trigger_0;
wire [`OUT_DPORT_DW-1:0] port_0_dt_o, port_1_dt_o, port_2_dt_o, port_3_dt_o;

// SG CDC path
wire  [167:0] tproc_sgcdc_0_axis_tdata;
wire          tproc_sgcdc_0_axis_tvalid;
logic         tproc_sgcdc_0_axis_tready;
wire  [167:0] sgcdc_sgt_0_axis_tdata;
wire          sgcdc_sgt_0_axis_tvalid;
logic         sgcdc_sgt_0_axis_tready;
wire  [159:0] sgt_sg_0_axis_tdata;
wire          sgt_sg_0_axis_tvalid;
logic         sgt_sg_0_axis_tready;

// RO CDC path
wire  [167:0] tproc_rocdc_0_axis_tdata;
wire          tproc_rocdc_0_axis_tvalid;
logic         tproc_rocdc_0_axis_tready;
wire  [167:0] rocdc_rot_0_axis_tdata;
wire          rocdc_rot_0_axis_tvalid;
logic         rocdc_rot_0_axis_tready;
wire  [87:0]  rot_ro_0_axis_tdata;
wire          rot_ro_0_axis_tvalid;
logic         rot_ro_0_axis_tready;

// QNet/QCom/Periph
wire         qnet_en_o;
wire  [4:0]  qnet_op_o;
wire  [31:0] qnet_a_dt_o, qnet_b_dt_o, qnet_c_dt_o, qnet_d_dt_o;
reg          qnet_rdy_i;
reg  [31:0]  qnet_dt_i [2];
reg          qcom_rdy_i, qp2_rdy_i;
reg  [31:0]  qcom_dt_i [2];
wire         periph_en_o;
wire  [4:0]  periph_op_o;
wire  [31:0] periph_a_dt_o, periph_b_dt_o, periph_c_dt_o, periph_d_dt_o;
reg          periph_rdy_i;
reg  [31:0]  periph_dt_i [2];
reg  [31:0]  qp1_dt_i [2];
reg  [31:0]  qp2_dt_i [2];

reg  s0_axis_tvalid, s1_axis_tvalid;
reg  [15:0] waves, wtime;
reg  [31:0] axi_dt;

reg  proc_start_i, proc_stop_i;
reg  core_start_i, core_stop_i;
reg  time_rst_i, time_init_i, time_updt_i;
reg  [47:0] offset_dt_i;
wire [47:0] t_time_abs_o;
wire [31:0] ps_debug_do;

// QP1 loopback
wire         qp1_en_o;
reg          qp1_en_r;
reg  [31:0]  qp1_a_dt_r, qp1_b_dt_r;
wire [31:0]  qp1_a_dt_o, qp1_b_dt_o, qp1_c_dt_o, qp1_d_dt_o;
always_ff @(posedge c_clk) begin
   qp1_en_r   <= qp1_en_o;
   qp1_a_dt_r <= qp1_a_dt_o;
   qp1_b_dt_r <= qp1_b_dt_o;
end
assign qp1_rdy_i   = ~qp1_en_r;
assign qp1_dt_i[0] = qp1_a_dt_r;
assign qp1_dt_i[1] = qp1_b_dt_r;
assign qp1_vld_i   = qp1_en_r;

wire port_0_vld, qnet_vld_i, qnet_flag_i, periph_flag_i, ext_flag_i;
assign port_0_dt_i   = port_1_dt_o;
assign port_0_vld    = port_0_dt_o[0];
assign qnet_vld_i    = t_time_abs_o[3] & t_time_abs_o[2] & t_time_abs_o[1];
assign qnet_flag_i   = ~t_time_abs_o[5] & ~t_time_abs_o[4] &  t_time_abs_o[3];
assign periph_flag_i = ~t_time_abs_o[5] &  t_time_abs_o[4] &  t_time_abs_o[3];
assign ext_flag_i    =  t_time_abs_o[5] &  t_time_abs_o[4] &  t_time_abs_o[3];

// DAC/ADC connections
logic                axis_sg_dac_tready;
logic                axis_sg_dac_tvalid;
logic [N_DDS*16-1:0] axis_sg_dac_tdata;
logic                rf_signal_valid;
logic [8*16-1:0]     rf_signal_data;
logic                axis_adc_ro_tready;
logic                axis_adc_ro_tvalid;
logic [8*16-1:0]     axis_adc_ro_tdata;

// SG envelope load signals
wire   sg_s0_axis_aclk = s_ps_dma_aclk;
logic  [31:0] sg_s0_axis_tdata;
logic         sg_s0_axis_tready;
logic         sg_s0_axis_tvalid;
logic         tb_load_mem, tb_load_mem_done;

// Avg buffer DEC output readiness
logic m1_axis_buf_dec_tready;

//----------------------------------------------------
// TPROC AXI-Lite wires + register address offsets
//----------------------------------------------------
wire [7:0]  s_axi_tproc_awaddr;   wire [2:0]  s_axi_tproc_awprot;
wire        s_axi_tproc_awvalid;  wire        s_axi_tproc_awready;
wire [31:0] s_axi_tproc_wdata;    wire [3:0]  s_axi_tproc_wstrb;
wire        s_axi_tproc_wvalid;   wire        s_axi_tproc_wready;
wire  [1:0] s_axi_tproc_bresp;    wire        s_axi_tproc_bvalid;
wire        s_axi_tproc_bready;
wire [7:0]  s_axi_tproc_araddr;   wire [2:0]  s_axi_tproc_arprot;
wire        s_axi_tproc_arvalid;  wire        s_axi_tproc_arready;
wire  [31:0] s_axi_tproc_rdata;   wire  [1:0] s_axi_tproc_rresp;
wire         s_axi_tproc_rvalid;  wire        s_axi_tproc_rready;

parameter REG_TPROC_CTRL   = 0  * 4;
parameter REG_TPROC_CFG    = 1  * 4;
parameter REG_MEM_ADDR     = 2  * 4;
parameter REG_MEM_LEN      = 3  * 4;
parameter REG_MEM_DT_I     = 4  * 4;
parameter REG_AXI_W_DT1    = 5  * 4;
parameter REG_AXI_W_DT2    = 6  * 4;
parameter REG_CORE_CFG     = 7  * 4;
parameter REG_AXI_DT_SRC   = 8  * 4;
parameter REG_MEM_DT_O     = 10 * 4;
parameter REG_AXI_R_DT1    = 11 * 4;
parameter REG_AXI_R_DT2    = 12 * 4;
parameter REG_TIME_USR     = 13 * 4;
parameter REG_TPROC_STATUS = 14 * 4;
parameter REG_TPROC_DEBUG  = 15 * 4;

axi_mst_0 u_axi_mst_tproc_0 (
   .aclk          (s_ps_dma_aclk       ),
   .aresetn       (s_ps_dma_aresetn    ),
   .m_axi_araddr  (s_axi_tproc_araddr  ),
   .m_axi_arprot  (s_axi_tproc_arprot  ),
   .m_axi_arready (s_axi_tproc_arready ),
   .m_axi_arvalid (s_axi_tproc_arvalid ),
   .m_axi_awaddr  (s_axi_tproc_awaddr  ),
   .m_axi_awprot  (s_axi_tproc_awprot  ),
   .m_axi_awready (s_axi_tproc_awready ),
   .m_axi_awvalid (s_axi_tproc_awvalid ),
   .m_axi_bready  (s_axi_tproc_bready  ),
   .m_axi_bresp   (s_axi_tproc_bresp   ),
   .m_axi_bvalid  (s_axi_tproc_bvalid  ),
   .m_axi_rdata   (s_axi_tproc_rdata   ),
   .m_axi_rready  (s_axi_tproc_rready  ),
   .m_axi_rresp   (s_axi_tproc_rresp   ),
   .m_axi_rvalid  (s_axi_tproc_rvalid  ),
   .m_axi_wdata   (s_axi_tproc_wdata   ),
   .m_axi_wready  (s_axi_tproc_wready  ),
   .m_axi_wstrb   (s_axi_tproc_wstrb   ),
   .m_axi_wvalid  (s_axi_tproc_wvalid  )
);

//----------------------------------------------------
// AXIS QICK PROCESSOR
//----------------------------------------------------
axis_qick_processor #(
   .DUAL_CORE      ( `DUAL_CORE     ),
   .GEN_SYNC       ( `GEN_SYNC      ),
   .IO_CTRL        ( `IO_CTRL       ),
   .DEBUG          ( `DEBUG         ),
   .TNET           ( `TNET          ),
   .QCOM           ( `QCOM          ),
   .CUSTOM_PERIPH  ( `CUSTOM_PERIPH ),
   .LFSR           ( `LFSR          ),
   .DIVIDER        ( `DIVIDER       ),
   .ARITH          ( `ARITH         ),
   .TIME_READ      ( `TIME_READ     ),
   .FIFO_DEPTH     ( `FIFO_DEPTH    ),
   .PMEM_AW        ( `PMEM_AW       ),
   .DMEM_AW        ( `DMEM_AW       ),
   .WMEM_AW        ( `WMEM_AW       ),
   .REG_AW         ( `REG_AW        ),
   .IN_PORT_QTY    ( `IN_PORT_QTY   ),
   .OUT_TRIG_QTY   ( `OUT_TRIG_QTY  ),
   .OUT_DPORT_QTY  ( `OUT_DPORT_QTY ),
   .OUT_DPORT_DW   ( `OUT_DPORT_DW  ),
