   .qcom_op_o           ( qcom_op_o          ),
   .qcom_dt_o           ( qcom_dt_o          ),
   .qcom_rdy_i          ( qcom_rdy_i         ),
   .qcom_dt1_i          ( qcom_dt_i[0]       ),
   .qcom_dt2_i          ( qcom_dt_i[1]       ),
   .qcom_vld_i          ( qcom_vld_i         ),
   .qcom_flag_i         ( qcom_flag_i        ),
   .qp1_en_o            ( qp1_en_o           ),
   .qp1_op_o            ( qp1_op_o           ),
   .qp1_a_dt_o          ( qp1_a_dt_o         ),
   .qp1_b_dt_o          ( qp1_b_dt_o         ),
