//============================================================
// TEST STIMULI — QickEmu replay
//============================================================

initial begin
   // Create and start VIP agents
   axi_mst_tproc_agent = new("axi_mst_tproc VIP Agent",  tb_qick_emu.u_axi_mst_tproc_0.inst.IF);
   axi_mst_sg_agent    = new("axi_mst_sg_0 VIP Agent",   tb_qick_emu.u_axi_mst_sg_0.inst.IF);
   axi_mst_avg_agent   = new("axi_mst_avg_0 VIP Agent",  tb_qick_emu.u_axi_mst_avg_0.inst.IF);
   axi_mst_qemu_agent  = new("axi_mst_qemu_0 VIP Agent", tb_qick_emu.u_axi_mst_qemu_0.inst.IF);
   axi_mst_tproc_agent.set_agent_tag("axi_mst_tproc VIP");
   axi_mst_sg_agent.set_agent_tag("axi_mst_sg_0 VIP");
   axi_mst_avg_agent.set_agent_tag("axi_mst_avg_0 VIP");
   axi_mst_qemu_agent.set_agent_tag("axi_mst_qemu_0 VIP");
   axi_mst_tproc_agent.start_master();
   axi_mst_sg_agent.start_master();
   axi_mst_avg_agent.start_master();
   axi_mst_qemu_agent.start_master();

   // Initialize all control signals
   qnet_dt_i              = '{default:'0};
   rst_ni                 = 1'b0;
   axi_dt                 = 0;
   s1_axis_tvalid         = 1'b0;
   port_1_dt_i            = 0;
   qcom_rdy_i             = 0;
   qp2_rdy_i              = 0;
   periph_dt_i            = '{default:'0};
   qnet_rdy_i             = 0;
   proc_start_i           = 1'b0;
   proc_stop_i            = 1'b0;
   core_start_i           = 1'b0;
   core_stop_i            = 1'b0;
   time_rst_i             = 1'b0;
   time_init_i            = 1'b0;
   time_updt_i            = 1'b0;
   offset_dt_i            = 0;
   tb_load_mem            = 1'b0;
   tb_load_mem_done       = 1'b0;
   sg_s0_axis_tvalid      = 0;
   sg_s0_axis_tdata       = 0;
   m1_axis_buf_dec_tready = 1'b1;
   m_dma_axis_tready_i    = 1'b1;
   s_dma_axis_tdata_i     = 0;
   s_dma_axis_tlast_i     = 0;
   s_dma_axis_tvalid_i    = 0;
   #10ns;

   // Assert then release reset
   repeat(16) @(posedge s_ps_dma_aclk); #0.1ns;
   rst_ni = 1'b1;

   #100ns;

   // Load tproc memories AFTER reset (BRAM init is complete)
   tproc_load_mem_emu(EMU_DIR);

   #1us;

   // Load signal generator envelope table (if any shaped pulses used)
   sg_load_mem_emu(EMU_DIR, 0);

   #1us;

   // Replay all AXI-Lite transactions
   begin
      string replay_path;
      replay_path = {EMU_DIR, "/axi_replay.txt"};
      $display("### %t - Replaying AXI transactions from %s ###",
               $realtime(), replay_path);
      replay_axi_writes(replay_path);
   end

// Wait for program execution to complete.
   #(TEST_RUN_TIME);

   // ===== READ CAPTURED DATA FROM AVG BUFFER =====
   $display("### %t - Reading avg/dec buffers ###", $realtime());

   // Read averaged data
   @(posedge s_ps_dma_aclk); #0.1;
   axi_mst_avg_agent.AXI4LITE_WRITE_BURST(AVG_DR_LEN_REG, prot, 32'h00000001, resp);
   #100ns;
   @(posedge s_ps_dma_aclk); #0.1;
   axi_mst_avg_agent.AXI4LITE_WRITE_BURST(AVG_DR_START_REG, prot, 32'h00000001, resp);
   #100ns;
   @(posedge s_ps_dma_aclk); #0.1;
   axi_mst_avg_agent.AXI4LITE_WRITE_BURST(AVG_DR_START_REG, prot, 32'h00000000, resp);
   #1us;

   // Read decimated data
   @(posedge s_ps_dma_aclk); #0.1;
   axi_mst_avg_agent.AXI4LITE_WRITE_BURST(BUF_DR_LEN_REG, prot, 32'h0000039A, resp);
   #100ns;
   @(posedge s_ps_dma_aclk); #0.1;
   axi_mst_avg_agent.AXI4LITE_WRITE_BURST(BUF_DR_START_REG, prot, 32'h00000001, resp);
   #100ns;
   @(posedge s_ps_dma_aclk); #0.1;
   axi_mst_avg_agent.AXI4LITE_WRITE_BURST(BUF_DR_START_REG, prot, 32'h00000000, resp);

   // Wait for data to drain
   #50us;
   // ===== END READ =====

   $display("*** End Test ***");
   // Close CSV files before finishing
   $fclose(dac_csv_fd);
   $fclose(avg_csv_fd);
   $fclose(dec_csv_fd);
   $finish();
end


//============================================================
// CSV Output Logging
//============================================================

// File descriptors — opened at time 0
integer dac_csv_fd;   // DAC output samples (one row per sg_clk when valid)
integer avg_csv_fd;   // Averaged IQ from avg_buffer m0 (one row per word)
integer dec_csv_fd;   // Decimated IQ from avg_buffer m1 (one row per word)

initial begin
   string dac_csv_path, avg_csv_path, dec_csv_path;
   dac_csv_path = {EMU_DIR, "/dac_out.csv"};
   avg_csv_path = {EMU_DIR, "/avg_out.csv"};
   dec_csv_path = {EMU_DIR, "/dec_out.csv"};
   dac_csv_fd = $fopen(dac_csv_path, "w");
   avg_csv_fd = $fopen(avg_csv_path, "w");
   dec_csv_fd = $fopen(dec_csv_path, "w");

   // Write headers
   $fwrite(dac_csv_fd, "time_ps");
   for (int i = 0; i < N_DDS; i++) $fwrite(dac_csv_fd, ",s%0d", i);
   $fwrite(dac_csv_fd, "\n");

   $fwrite(avg_csv_fd, "time_ps,I,Q\n");
   $fwrite(dec_csv_fd, "time_ps,I,Q\n");
end

// DAC samples: N_DDS=16 parallel samples per sg_clk when the SG is active.
// Columns: time_ps, s0..s15  (signed 16-bit each)
always @(posedge sg_clk) begin
   if (axis_sg_dac_tvalid) begin
      $fwrite(dac_csv_fd, "%0t", $time);
      for (int i = 0; i < N_DDS; i++)
         $fwrite(dac_csv_fd, ",%0d", $signed(axis_sg_dac_tdata[16*i +: 16]));
      $fwrite(dac_csv_fd, "\n");
   end
end

// Averaged IQ: 64-bit word, [31:0]=I  [63:32]=Q  (32-bit signed each).
// One accumulated sum per trigger window.
always @(posedge s_ps_dma_aclk) begin
   if (m0_axis_buf_avg_tvalid)
      $fwrite(avg_csv_fd, "%0t,%0d,%0d\n", $time,
              $signed(m0_axis_buf_avg_tdata[31:0]),
              $signed(m0_axis_buf_avg_tdata[63:32]));
end

// Decimated IQ: 32-bit word, [15:0]=I  [31:16]=Q  (16-bit signed each).
// Raw downconverted stream at readout clock rate.
always @(posedge s_ps_dma_aclk) begin
   if (m1_axis_buf_dec_tvalid)
      $fwrite(dec_csv_fd, "%0t,%0d,%0d\n", $time,
              $signed(m1_axis_buf_dec_tdata[15:0]),
              $signed(m1_axis_buf_dec_tdata[31:16]));
end


//----------------------------------------------------
// TASKS
//----------------------------------------------------

// Load tproc program and wave memories from QickEmu-generated files.
task tproc_load_mem_emu(string emu_dir);
   string pmem_file, wmem_file;
   pmem_file = {emu_dir, "/pmem.mem"};
   wmem_file = {emu_dir, "/wmem.mem"};
   $display("### Loading tproc memories from: %s ###", emu_dir);
   $display("### pmem_file: %s ###", pmem_file);
   $display("### wmem_file: %s ###", wmem_file);
   $readmemh(pmem_file, AXIS_QPROC.QPROC.CORE_0.CORE_MEM.P_MEM.RAM);
   $readmemh(wmem_file, AXIS_QPROC.QPROC.CORE_0.CORE_MEM.W_MEM.RAM);
   $display("### VERIFY P_MEM[1] = %h ###", AXIS_QPROC.QPROC.CORE_0.CORE_MEM.P_MEM.RAM[1]);
   $display("### tproc memories loaded ###");
endtask

// Load signal generator envelope table via AXIS streaming.
// sg_ch: channel index (used to select sgmem_ch{sg_ch}.mem).
// If the file doesn't exist (e.g., const-style pulse with no envelope), prints a
// message and returns without driving the AXIS interface.
task sg_load_mem_emu(string emu_dir, int sg_ch);
   string sg_file;
   integer fd, vali, valq;
   bit signed [15:0] ii, qq;

   sg_file = $sformatf("%s/sgmem_ch%0d.mem", emu_dir, sg_ch);
   fd = $fopen(sg_file, "r");
   if (fd == 0) begin
      $display("### %t - SG ch%0d: no envelope file %s (const pulse or not used) ###",
               $realtime(), sg_ch, sg_file);
      return;
   end

   $display("### %t - Loading SG ch%0d envelope from %s ###",
            $realtime(), sg_ch, sg_file);

   // Set envelope table start address to 0 and enable write
   @(posedge s_ps_dma_aclk); #0.1;
   axi_mst_sg_agent.AXI4LITE_WRITE_BURST(SG_ADDR_START_ADDR, prot, 0, resp);
   #100ns;
   axi_mst_sg_agent.AXI4LITE_WRITE_BURST(SG_ADDR_WE, prot, 1, resp);
   #100ns;

   tb_load_mem = 1;
   wait(sg_s0_axis_tready);

   while ($fscanf(fd, "%d,%d", vali, valq) == 2) begin
      ii = vali;
      qq = valq;
      @(posedge sg_s0_axis_aclk);
      sg_s0_axis_tvalid = 1;
      sg_s0_axis_tdata  = {qq, ii};
   end
   $fclose(fd);

   @(posedge sg_s0_axis_aclk);
   sg_s0_axis_tvalid = 0;
   tb_load_mem_done  = 1;

   $display("### %t - SG ch%0d envelope loaded ###", $realtime(), sg_ch);
endtask


// Replay all AXI-Lite write transactions from a text file.
// File format (generated by QickEmu.export_vivado_files()):
//   # comment lines are ignored
//   XXXXXXXX YYYYYYYY   (8-hex-digit addr, space, 8-hex-digit data)
// Each transaction is routed to the correct VIP agent based on address range.
task replay_axi_writes(string replay_file);
   integer fd;
   string  line;
   integer addr_val, data_val;
   integer n_routed, n_skipped;

   fd = $fopen(replay_file, "r");
   if (fd == 0) begin
      $display("ERROR: Cannot open AXI replay file: %s", replay_file);
      $display("       Run QickEmu.export_vivado_files() to generate it.");
      return;
   end

   n_routed  = 0;
   n_skipped = 0;

   while ($fgets(line, fd)) begin
      if (line.len() < 2)        continue;
      if (line.substr(0,0) == "#") continue;  // comment
      if ($sscanf(line, "%h %h", addr_val, data_val) == 2) begin
         route_and_write(addr_val, data_val);
         n_routed++;
      end
   end
   $fclose(fd);

   $display("### AXI replay done: %0d transactions replayed ###", n_routed);
endtask


// Route an absolute-address AXI write to the correct VIP agent.
// Strips the base address to get the IP register offset.
task route_and_write(integer addr, integer data);
   integer offset;

   if (addr >= TPROC_BASE && addr < TPROC_BASE + 32'h10000) begin
      offset = addr - TPROC_BASE;
      @(posedge s_ps_dma_aclk); #0.1;
      axi_mst_tproc_agent.AXI4LITE_WRITE_BURST(offset, prot, data, resp);
   end
   else if (addr >= SG_BASE_LO && addr < SG_BASE_HI) begin
      // All gen IPs share the same VIP in this testbench.
      // The offset (low 16 bits) selects the register within the IP.
      offset = addr & 32'h0000FFFF;
      @(posedge s_ps_dma_aclk); #0.1;
      axi_mst_sg_agent.AXI4LITE_WRITE_BURST(offset, prot, data, resp);
   end
   else if (addr >= AVG_BASE_LO && addr < AVG_BASE_HI) begin
      offset = addr & 32'h0000FFFF;
      @(posedge s_ps_dma_aclk); #0.1;
      axi_mst_avg_agent.AXI4LITE_WRITE_BURST(offset, prot, data, resp);
   end
   else begin
      $display("WARNING: Unrouted AXI write addr=0x%08X data=0x%08X", addr, data);
   end
endtask

endmodule


//----------------------------------------------------
// DAC-ADC RF frontend model (loopback)
// Identical to model in tb_qick.sv.
//----------------------------------------------------
module model_DAC_ADC #(
   parameter integer DAC_W       = 16,
   parameter integer ADC_W       = 16,
   parameter integer BUFFER_SIZE = 16
)(
   input  wire clk_DAC,
   input  wire [DAC_W-1:0] dac_sample,
   input  wire clk_ADC,
   output logic [ADC_W-1:0] adc_sample,
   input  int  mode   // 0 = ZOH, 1 = linear interpolation
);
   real buffer_samples[BUFFER_SIZE];
   real buffer_times  [BUFFER_SIZE];
   int  wr_ptr = 0;
   real signal_in, sampled_ADC;

   initial begin
      for (int i = 0; i < BUFFER_SIZE; i++) begin
         buffer_samples[i] = 0.0;
         buffer_times  [i] = 0.0;
      end
   end

   always @(posedge clk_DAC) begin
      real t_now = $realtime * 1e-9;
      signal_in = $signed(dac_sample) / 2.0**(DAC_W-1);
      buffer_samples[wr_ptr] = signal_in;
      buffer_times  [wr_ptr] = t_now;
      wr_ptr = (wr_ptr + 1) % BUFFER_SIZE;
   end

   always @(posedge clk_ADC) begin
      real t_adc = $realtime * 1e-9;
      real val;
      case (mode)
         0: begin
            int idx_last = (wr_ptr + BUFFER_SIZE - 1) % BUFFER_SIZE;
            val = buffer_samples[idx_last];
         end
         1: begin
            int idx_curr = (wr_ptr + BUFFER_SIZE - 1) % BUFFER_SIZE;
            int idx_prev = (wr_ptr + BUFFER_SIZE - 2) % BUFFER_SIZE;
            real t1 = buffer_times  [idx_prev], t2 = buffer_times  [idx_curr];
            real y1 = buffer_samples[idx_prev], y2 = buffer_samples[idx_curr];
            if (t2 != t1) val = y1 + (t_adc - t1) * (y2 - y1)/(t2 - t1);
            else          val = y2;
         end
         default: val = 0.0;
      endcase
      if      (val >  1.0) sampled_ADC =  1.0;
      else if (val < -1.0) sampled_ADC = -1.0;
      else                 sampled_ADC =  val;
      adc_sample = sampled_ADC * $signed(2**(ADC_W-1)-1);
   end
endmodule
